function hasValidCustomSource() {
    const value = (source.getLoginInfoMap())['自定义源站'];
    return !(value == null || value === undefined || value == "" || String(value).trim() == "");
}

function showCustomSourceAlert() {
    const customSource = (source.getLoginInfoMap() || {})['自定义源站'];
    java.toast(
        "\n⚠️ 自定义源站配置提醒 ⚠️\n" +
        "──────────────────\n" +
        "检测到已设置自定义源站: \n✨" +
        "【" + (customSource || "空值") + "】✨\n" +
        "──────────────────\n" +
        "请前往「书源登录」清除配置\n" +
        "才能使指定源站切换生效"
    );
}

function updateConfig(key, value, message, gender) {
    if (key == "source" && hasValidCustomSource()) {
        showCustomSourceAlert();
        return;
    }

    try {
        var config = JSON.parse(source.getVariable());
        if (!config || !Array.isArray(config) || config.length === 0) {
            config = [{}];
        }
        config[0][key] = value;
        if (gender !== undefined) {
            config[0]["gender"] = gender;
        } else if (key == "source") {
        }

source.setVariable(JSON.stringify(config));
        java.toast(message || "设置已更新");
    } catch(e) {
        var newConfig = {[key]: value};
        if (gender !== undefined) {
            newConfig["gender"] = gender;
        }
        source.setVariable(JSON.stringify([newConfig]));
        java.toast(message || "初始化设置");
    }
}

this.sethost = function() {
    try {
        var config = JSON.parse(source.getVariable());
        if (!config || !Array.isArray(config) || config.length === 0) {
            config = [{host: hosts[0], localVersion: LOCAL_VERSION}];
        }

        if (hosts.length <= 1) {
            if (!config[0].host) {
                config[0].host = hosts[0];
            }
            if (!config[0].localVersion) {
                config[0].localVersion = LOCAL_VERSION;
            }
            source.setVariable(JSON.stringify(config));
            java.toast("当前服务器：" + config[0].host);
            return;
        }

        var currentHost = config[0].host || hosts[0];
        var currentIndex = hosts.indexOf(currentHost);
        var newIndex = (currentIndex + 1) % hosts.length;
        var newHost = hosts[newIndex];

        config[0].host = newHost;
        if (!config[0].localVersion) {
            config[0].localVersion = LOCAL_VERSION;
        }
        source.setVariable(JSON.stringify(config));
        java.toast("切换到：" + newHost);
    } catch(e) {
        source.setVariable(JSON.stringify([{host: hosts[0], localVersion: LOCAL_VERSION}]));
        java.toast("已初始化：" + hosts[0]);
    }
};

for (var i = 0; i < sourceList.length; i++) {
    (function() {
        var s = sourceList[i];
        this[s.n] = function() {
            if (hasValidCustomSource()) {
                showCustomSourceAlert();
                return;
            } if (s.g) {
                updateConfig("source", s.v, "\n已切换" + (s.v ? '到❇️' : '') + s.m +"❇️\n刷新发现页生效", s.g);
            } else {
                updateConfig("source", s.v, "\n已切换" + (s.v ? '到❇️' : '') + s.m +"❇️\n刷新发现页生效");
            }
        };
    }).call(this);
}

function get_cx() {
    try {
        var configStr = source.getVariable();
        if (!configStr || configStr.trim() == "") {
            configStr = JSON.stringify([{host: hosts[0], localVersion: LOCAL_VERSION}]);
            source.setVariable(configStr);
        }

        var config = JSON.parse(configStr);
        if (!config || !Array.isArray(config) || config.length === 0) {
            config = [{host: hosts[0], localVersion: LOCAL_VERSION}]; source.setVariable(JSON.stringify(config)); }
        if (!config[0].host) {
            config[0].host = hosts[0]; source.setVariable(JSON.stringify(config)); }
        if (!config[0].localVersion) {
            config[0].localVersion = LOCAL_VERSION; source.setVariable(JSON.stringify(config)); }
        var currentHost = config[0].host;
        var currentSource = config[0].source === null || config[0].source === "" 
            ? "☁️ 聚合搜索 ☁️" 
            : (sourceList.find(item => item.v == config[0].source)?.m || config[0].source);
        var customSource = (source.getLoginInfoMap())['自定义源站'] || "未设置";
        var customSourceStatus = hasValidCustomSource() ? "🔗 " + customSource : "当前未设置，示例：星星,笑佳人";
        var message = 
            "\n───────────────\n" +
            "☑️  配  置  状  态 ☑️\n" +
            "───────────────\n" +
            "🔘 服  务  器 🔘\n" + currentHost + "\n" +
            "───────────────\n" +
            "🌋 书  源 🌋\n" + currentSource + "\n" +
            "───────────────\n" +
            "❇️ 自 定 义 源 ❇️\n" + customSourceStatus + "\n" +
            "───────────────\n" +
            "\n✨ 提示：点击按钮切换配置";
        java.longToast(message);
    } catch(e) {
        var defaultConfig = [{host: hosts[0], localVersion: LOCAL_VERSION}]; source.setVariable(JSON.stringify(defaultConfig));
        java.toast("⚠️ 配置初始化完成，请重试");
    }
}

